using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
namespace 
{
    [ApiController]
    [Route("api/[controller]")]
    public class StreamBodyRouteController : ControllerBase
    {
        private readonly global::IStreamBodyRouteService iStreamBodyRouteService;
        public StreamBodyRouteController(global::IStreamBodyRouteService iStreamBodyRouteService)
        {
            this.iStreamBodyRouteService = iStreamBodyRouteService;
        }

        [Route("UploadFile/{id}")]
        [HttpPost]
        public void UploadFile([FromRoute] int id, [FromForm] __UploadFile_FormArg arg)
        {
            using var __sb_file = YS.Knife.StreamBody.FromStream(arg.file.OpenReadStream(), arg.file.ContentType, arg.file.FileName, arg.file.Length);
            this.iStreamBodyRouteService.UploadFile(id, __sb_file);
        }

        public record __UploadFile_FormArg(global::Microsoft.AspNetCore.Http.IFormFile file);
    }
}
